from dataclasses import dataclass, field


class GameConfig:
    def __init__(self, config: dict):
        self._config = config
        os.makedirs(config.get('data_dir', 'data'), exist_ok=True)

    def get(self, key: str):
        return self._config.get(key)


@dataclass
class Room:
    name: str = ''
    description: str = ''
    exits: dict = field(default_factory=dict)
    items: list = field(default_factory=list)


class WorldLoader:
    def load_world(self, filepath: str) -> dict:
        with open(filepath) as f:
            raw = json.load(f)
        rooms = {}
        for name, data in raw.items():
            rooms[name] = Room(
                name=name,
                description=data['description'],
                exits=data.get('exits', {}),
                items=data.get('items', [])
            )
        return rooms


def save_world(rooms: dict, filepath: str) -> None:
    data = {}
    for name, room in rooms.items():
        data[name] = {
            'description': room.description,
            'exits': room.exits,
            'items': list(room.items)
        }
    with open(filepath, 'w') as f:
        json.dump(data, f, indent=2)


class GameWorld:
    def __init__(self):
        self._rooms = {}

    def add_room(self, room: Room) -> None:
        self._rooms[room.name] = room

    def get_room(self, name: str):
        return self._rooms.get(name)

    def get_exits(self, room_name: str) -> dict:
        room = self._rooms.get(room_name)
        return room.exits if room else {}


class Player:
    def __init__(self, name: str, current_room: str, health: int = 100,
                 inventory: list = None, gold: int = 0):
        self.name = name
        self.current_room = current_room
        self.health = health
        self.inventory = inventory or []
        self.gold = gold


def move_player(game_world: GameWorld, player: Player, direction: str) -> bool:
    exits = game_world.get_exits(player.current_room)
    if direction in exits:
        player.current_room = exits[direction]
        return True
    return False


class Item:
    def __init__(self, name: str, item_type: str, value: int, description: str):
        self.name = name
        self.item_type = item_type
        self.value = value
        self.description = description


class Inventory:
    def __init__(self):
        self._items = []

    def add(self, item: Item) -> None:
        self._items.append(item)

    def remove(self, name: str) -> bool:
        for item in self._items:
            if item.name == name:
                self._items.remove(item)
                return True
        return False

    def find(self, name: str):
        for item in self._items:
            if item.name == name:
                return item
        return None

    def list_items(self) -> list:
        return list(self._items)

    def total_value(self) -> int:
        return sum(item.value for item in self._items)


class ItemDatabase:
    def __init__(self):
        self._items = {}

    def register(self, item: Item) -> None:
        self._items[item.name] = item

    def get(self, name: str):
        return self._items.get(name)

    def all_items(self) -> list:
        return list(self._items.values())


class CommandParser:
    KNOWN_COMMANDS = ['go', 'take', 'attack', 'look', 'inventory', 'say', 'use', 'help']

    def parse(self, raw_input: str) -> dict:
        text = raw_input.strip()
        if not text:
            return {'command': 'unknown', 'args': ''}
        parts = text.split(None, 1)
        cmd = parts[0].lower()
        args = parts[1] if len(parts) > 1 else ''
        if cmd in self.KNOWN_COMMANDS:
            return {'command': cmd, 'args': args}
        return {'command': 'unknown', 'args': text}


class ClientSession(threading.Thread):
    def __init__(self, client_socket: socket.socket, address: tuple,
                 player_name: str = ''):
        super().__init__(daemon=True)
        self.client_socket = client_socket
        self.address = address
        self.player_name = player_name
        self.running = False

    def send_message(self, message: dict) -> None:
        data = json.dumps(message).encode('utf-8') + b'\n'
        self.client_socket.sendall(data)

    def receive_message(self) -> dict:
        try:
            buffer = b''
            while b'\n' not in buffer:
                chunk = self.client_socket.recv(4096)
                if not chunk:
                    return {}
                buffer += chunk
            line = buffer.split(b'\n')[0]
            return json.loads(line.decode('utf-8'))
        except Exception:
            return {}

    def run(self):
        self.running = True


class GameServer:
    def __init__(self, host: str = 'localhost', port: int = 5555):
        self.host = host
        self.port = port
        self._socket = None
        self._running = False
        self._sessions = []

    def start(self) -> None:
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._socket.bind((self.host, self.port))
        self._socket.listen(5)
        self._running = True

    def stop(self) -> None:
        self._running = False
        if self._socket:
            self._socket.close()


class GameProtocol:
    @staticmethod
    def encode(message: dict) -> bytes:
        return json.dumps(message).encode('utf-8') + b'\n'

    @staticmethod
    def decode(data: bytes) -> dict:
        return json.loads(data.strip().decode('utf-8'))


class GameClient:
    def __init__(self):
        self._socket = None
        self._connected = False

    def connect(self, host: str, port: int) -> None:
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.connect((host, port))
        self._connected = True

    def send_command(self, command: dict) -> None:
        if self._connected:
            self._socket.sendall(GameProtocol.encode(command))

    def receive_response(self) -> dict:
        if not self._connected:
            return {}
        try:
            buffer = b''
            while b'\n' not in buffer:
                chunk = self._socket.recv(4096)
                if not chunk:
                    return {}
                buffer += chunk
            return GameProtocol.decode(buffer.split(b'\n')[0])
        except Exception:
            return {}

    def disconnect(self) -> None:
        self._connected = False
        if self._socket:
            self._socket.close()


class GameDatabase:
    def __init__(self, db_path: str = ':memory:'):
        self.db_path = db_path
        self._conn = sqlite3.connect(db_path)
        self._create_tables()

    def _create_tables(self):
        c = self._conn.cursor()
        c.execute('''CREATE TABLE IF NOT EXISTS players
                     (name TEXT PRIMARY KEY, health INTEGER,
                      room TEXT, gold INTEGER)''')
        c.execute('''CREATE TABLE IF NOT EXISTS inventory
                     (player_name TEXT, item_id TEXT)''')
        c.execute('''CREATE TABLE IF NOT EXISTS world_state
                     (key TEXT PRIMARY KEY, value TEXT)''')
        self._conn.commit()

    def save_player(self, player: Player) -> None:
        c = self._conn.cursor()
        c.execute('INSERT OR REPLACE INTO players VALUES (?, ?, ?, ?)',
                  (player.name, player.health, player.current_room, player.gold))
        c.execute('DELETE FROM inventory WHERE player_name = ?', (player.name,))
        for item_id in player.inventory:
            c.execute('INSERT INTO inventory VALUES (?, ?)', (player.name, item_id))
        self._conn.commit()

    def load_player(self, name: str):
        c = self._conn.cursor()
        c.execute('SELECT name, health, room, gold FROM players WHERE name = ?', (name,))
        row = c.fetchone()
        if not row:
            return None
        c.execute('SELECT item_id FROM inventory WHERE player_name = ?', (name,))
        items = [r[0] for r in c.fetchall()]
        return Player(row[0], row[2], row[1], items, row[3])

    def save_world_state(self, key: str, value: str) -> None:
        c = self._conn.cursor()
        c.execute('INSERT OR REPLACE INTO world_state VALUES (?, ?)', (key, value))
        self._conn.commit()

    def load_world_state(self, key: str) -> str:
        c = self._conn.cursor()
        c.execute('SELECT value FROM world_state WHERE key = ?', (key,))
        row = c.fetchone()
        return row[0] if row else ''

    def close(self) -> None:
        if self._conn:
            self._conn.close()


class Enemy:
    def __init__(self, name: str, health: int, attack: int, loot: list = None):
        self.name = name
        self.health = health
        self.attack = attack
        self.loot = loot or []


class CombatSystem:
    def initiate_combat(self, player: Player, enemy: Enemy) -> str:
        return f"{player.name} engages {enemy.name} in combat!"

    def calculate_damage(self, base_attack: int) -> int:
        low = base_attack // 2
        high = base_attack + base_attack // 2
        return random.randint(low, high)

    def attack(self, attacker_attack: int, defender_health: int) -> int:
        damage = self.calculate_damage(attacker_attack)
        return defender_health - damage

    def is_defeated(self, health: int) -> bool:
        return health <= 0

    def award_loot(self, player: Player, enemy: Enemy) -> list:
        awarded = list(enemy.loot)
        player.inventory.extend(awarded)
        return awarded


